// Package checks implements the language-agnostic pre-merge check protocol.
//
// A check is a project-declared mechanical gate evaluated before a worker's
// worktree is merged back. Each check is one YAML file under
// .ddx/checks/*.yaml describing a command to run and the situations it
// applies to (path globs, bead labels). The check command is invoked as a
// subprocess with the following environment variables injected:
//
//	BEAD_ID       — the bead being evaluated
//	DIFF_BASE     — git revision the work started from
//	DIFF_HEAD     — current worktree HEAD
//	PROJECT_ROOT  — absolute path to the project root
//	EVIDENCE_DIR  — directory the check must write its result file into
//	RUN_ID        — unique identifier for this evaluation run
//
// The check writes its result to ${EVIDENCE_DIR}/${name}.json with shape:
//
//	{
//	  "status":   "pass" | "block" | "error",
//	  "message":  "<human-readable summary>",
//	  "violations": [
//	    {"file": "...", "line": 0, "symbol": "...", "kind": "...", "detail": "..."}
//	  ]
//	}
//
// Exit code 0 indicates the check ran to completion (the status field in the
// result file is authoritative). A non-zero exit, a missing result file, or
// an unparseable result file is treated as status=error.
package checks

// Status enumerates the three possible check outcomes.
type Status string

const (
	StatusPass  Status = "pass"
	StatusBlock Status = "block"
	StatusError Status = "error"
)

// HookPreMerge is the only currently supported lifecycle hook.
const HookPreMerge = "pre_merge"

// Check is the parsed representation of one .ddx/checks/*.yaml file.
type Check struct {
	// Name uniquely identifies the check; also the basename of its result
	// file (${EVIDENCE_DIR}/${Name}.json). Required.
	Name string `yaml:"name"`
	// Command is the shell command to execute. Required. Run via
	// `sh -c <command>` so projects can use pipes/redirection.
	Command string `yaml:"command"`
	// When is the lifecycle hook the check binds to. Currently only
	// "pre_merge" is supported. Required.
	When string `yaml:"when"`
	// AppliesTo gates whether this check runs for a given (paths, labels)
	// invocation context. Zero value means "always".
	AppliesTo AppliesTo `yaml:"applies_to"`

	// SourceFile records the on-disk path the check was loaded from
	// (used for diagnostics). Not part of the YAML schema.
	SourceFile string `yaml:"-"`
}

// AppliesTo declares the conditions under which a check is evaluated.
//
// Semantics:
//   - If neither Paths nor Labels is set, the check ALWAYS applies.
//   - If Paths is set, the check applies when any changed path matches
//     any glob (filepath.Match semantics, evaluated against the path
//     relative to PROJECT_ROOT).
//   - If Labels is set, the check applies when the bead carries any of
//     the listed labels.
//   - If both are set, EITHER a matching path OR a matching label causes
//     the check to apply (logical OR).
type AppliesTo struct {
	Paths  []string `yaml:"paths,omitempty"`
	Labels []string `yaml:"labels,omitempty"`
}

// Result is the parsed outcome of running one check.
type Result struct {
	Name       string      `json:"name"`
	Status     Status      `json:"status"`
	Message    string      `json:"message,omitempty"`
	Violations []Violation `json:"violations,omitempty"`

	// ExitCode and Stderr are captured by the runner for diagnostics
	// when status=error. Not part of the on-disk JSON contract.
	ExitCode int    `json:"-"`
	Stderr   string `json:"-"`
}

// Violation describes one offending location reported by a check.
type Violation struct {
	File   string `json:"file,omitempty"`
	Line   int    `json:"line,omitempty"`
	Symbol string `json:"symbol,omitempty"`
	Kind   string `json:"kind,omitempty"`
	Detail string `json:"detail,omitempty"`
}

// InvocationContext bundles the runtime values injected as environment
// variables into each check command, plus the bead labels and changed
// paths used to evaluate AppliesTo filtering.
type InvocationContext struct {
	BeadID       string
	DiffBase     string
	DiffHead     string
	ProjectRoot  string
	EvidenceDir  string
	RunID        string
	BeadLabels   []string
	ChangedPaths []string
}

package checks

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"

	"gopkg.in/yaml.v3"
)

// LoadDir reads all *.yaml and *.yml files in dir as Check definitions.
// If dir does not exist, returns (nil, nil) — projects without a checks
// directory have no checks. Any unreadable file, malformed YAML, or
// unknown field is reported with the source file and (when available)
// line:column.
func LoadDir(dir string) ([]Check, error) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("checks: read dir %s: %w", dir, err)
	}

	var paths []string
	for _, e := range entries {
		if e.IsDir() {
			continue
		}
		ext := filepath.Ext(e.Name())
		if ext != ".yaml" && ext != ".yml" {
			continue
		}
		paths = append(paths, filepath.Join(dir, e.Name()))
	}
	sort.Strings(paths)

	out := make([]Check, 0, len(paths))
	seen := make(map[string]string, len(paths))
	for _, p := range paths {
		c, err := LoadFile(p)
		if err != nil {
			return nil, err
		}
		if prior, dup := seen[c.Name]; dup {
			return nil, fmt.Errorf("checks: duplicate check name %q in %s (also defined in %s)", c.Name, p, prior)
		}
		seen[c.Name] = p
		out = append(out, c)
	}
	return out, nil
}

// LoadFile parses a single check definition file. Unknown fields and
// malformed YAML are reported with file:line context.
func LoadFile(path string) (Check, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return Check{}, fmt.Errorf("checks: read %s: %w", path, err)
	}
	dec := yaml.NewDecoder(newBytesReader(data))
	dec.KnownFields(true)
	var c Check
	if err := dec.Decode(&c); err != nil {
		return Check{}, fmt.Errorf("checks: parse %s: %w", path, err)
	}
	c.SourceFile = path
	if err := c.Validate(); err != nil {
		return Check{}, fmt.Errorf("checks: %s: %w", path, err)
	}
	return c, nil
}

// Validate enforces required-field rules on a parsed check.
func (c *Check) Validate() error {
	if c.Name == "" {
		return fmt.Errorf("missing required field: name")
	}
	if c.Command == "" {
		return fmt.Errorf("missing required field: command")
	}
	if c.When == "" {
		return fmt.Errorf("missing required field: when")
	}
	if c.When != HookPreMerge {
		return fmt.Errorf("unsupported hook %q (only %q is supported)", c.When, HookPreMerge)
	}
	return nil
}

// Applies reports whether the check should run for the given context.
func (c *Check) Applies(ctx InvocationContext) bool {
	a := c.AppliesTo
	if len(a.Paths) == 0 && len(a.Labels) == 0 {
		return true
	}
	for _, lbl := range a.Labels {
		for _, b := range ctx.BeadLabels {
			if lbl == b {
				return true
			}
		}
	}
	for _, glob := range a.Paths {
		for _, p := range ctx.ChangedPaths {
			if matched, _ := filepath.Match(glob, p); matched {
				return true
			}
			// Also try matching against just the basename so
			// patterns like "*.go" match deeply nested files.
			if matched, _ := filepath.Match(glob, filepath.Base(p)); matched {
				return true
			}
		}
	}
	return false
}

// bytesReader is a minimal wrapper so we can hand a []byte to yaml.NewDecoder
// without pulling in bytes.NewReader at call sites; used to keep imports tidy
// for callers of LoadFile.
type bytesReader struct {
	b   []byte
	pos int
}

func newBytesReader(b []byte) *bytesReader { return &bytesReader{b: b} }

func (r *bytesReader) Read(p []byte) (int, error) {
	if r.pos >= len(r.b) {
		return 0, errEOF
	}
	n := copy(p, r.b[r.pos:])
	r.pos += n
	return n, nil
}

// errEOF is returned when bytesReader is exhausted; matches io.EOF semantics
// without importing io into this small file.
var errEOF = fmt.Errorf("EOF")

